def factorial(n):
    # Write recursive factorial
    if n <= 1:
        return 1
    return n * factorial(n - 1)

def fibonacci(n):
    # Write recursive Fibonacci solver
    if n <= 0:
        return 0
    if n == 1:
        return 1
    return fibonacci(n - 1) + fibonacci(n - 2)
